func (s *Service) ensureDefaults() {
	if s.clock == nil {
		s.clock = serviceClock{}
	}
	if s.creationPolicy == nil {
		s.creationPolicy = defaultCreationPolicy{config: s.config}
	}
	if s.resolutionPolicy == nil {
		s.resolutionPolicy = defaultResolutionPolicy{}
	}
	if s.probabilityEngine == nil {
		s.probabilityEngine = defaultProbabilityEngine{}
	}
	if s.probabilityValidator == nil {
		s.probabilityValidator = defaultProbabilityValidator{}
	}
	if s.searchPolicy == nil {
		s.searchPolicy = defaultSearchPolicy{}
	}
	if s.metricsCalculator == nil {
		s.metricsCalculator = defaultMetricsCalculator{}
	}
	if s.leaderboardCalculator == nil {
		s.leaderboardCalculator = defaultLeaderboardCalculator{}
	}
	if s.statusPolicy == nil {
		s.statusPolicy = defaultStatusPolicy{}
	}
}

var (
	_ ServiceInterface = (*Service)(nil)
	_ Clock            = serviceClock{}
)

// MarketOverview represents enriched market data with calculations.
type MarketOverview struct {
	Market             *Market
	Creator            *CreatorSummary
	ProbabilityChanges []ProbabilityPoint
	LastProbability    float64
	NumUsers           int
	TotalVolume        int64
	MarketDust         int64
}

// Page represents pagination parameters.
type Page struct {
	Limit  int
	Offset int
}

// LeaderboardRow represents a single row in the market leaderboard.
type LeaderboardRow struct {
	Username       string
	Profit         int64
	CurrentValue   int64
	TotalSpent     int64
	Position       string
	YesSharesOwned int64
	NoSharesOwned  int64
	Rank           int
}

// ProbabilityProjectionRequest represents a request for probability projection.
type ProbabilityProjectionRequest struct {
	MarketID int64
	Amount   int64
	Outcome  string
}

// ProbabilityProjection represents the result of a probability projection.
